INSERT INTO public.sentences (id,list_id,ru,ru_stressed,translit,en,pl,de,sort_order) VALUES
('orderingfood-part-1-51','orderingfood-part-1','Я хотел бы забронировать столик.','Я хоте́л бы заброни́ровать сто́лик.','Ya khotel by zabronirovat stolik.','I would like to reserve a table.','Chciałbym zarezerwować stolik.','Ich möchte einen Tisch reservieren.',51),
('orderingfood-part-1-52','orderingfood-part-1','На сколько человек?','На ско́лько челове́к?','Na skolko chelovek?','For how many people?','Dla ilu osób?','Für wie viele Personen?',52),
('orderingfood-part-1-53','orderingfood-part-1','Столик на четыре человека.','Сто́лик на четы́ре челове́ка.','Stolik na chetyre cheloveka.','A table for four people.','Stolik dla czterech osób.','Ein Tisch für vier Personen.',53),
('orderingfood-part-1-54','orderingfood-part-1','У окна есть свободный столик?','У окна́ есть свобо́дный сто́лик?','U okna yest svobodnyy stolik?','Is there a free table by the window?','Czy jest wolny stolik przy oknie?','Gibt es einen freien Tisch am Fenster?',54),
('orderingfood-part-1-55','orderingfood-part-1','Да, пожалуйста.','Да, пожа́луйста.','Da, pozhaluysta.','Yes, please.','Tak, poproszę.','Ja, bitte.',55),
('orderingfood-part-1-56','orderingfood-part-1','Можно посмотреть меню напитков?','Мо́жно посмотре́ть меню́ напи́тков?','Mozhno posmotret menyu napitkov?','Can I see the drink menu?','Czy mogę zobaczyć menu napojów?','Kann ich die Getränkekarte sehen?',56),
('orderingfood-part-1-57','orderingfood-part-1','Что вы будете пить?','Что вы бу́дете пить?','Chto vy budete pit?','What would you like to drink?','Co będziecie pić?','Was möchten Sie trinken?',57),
('orderingfood-part-1-58','orderingfood-part-1','Я буду воду без газа.','Я бу́ду во́ду без га́за.','Ya budu vodu bez gaza.','I will have still water.','Wezmę wodę niegazowaną.','Ich nehme stilles Wasser.',58),
('orderingfood-part-1-59','orderingfood-part-1','Я буду воду с газом.','Я бу́ду во́ду с га́зом.','Ya budu vodu s gazom.','I will have sparkling water.','Wezmę wodę gazowaną.','Ich nehme Sprudelwasser.',59),
('orderingfood-part-1-60','orderingfood-part-1','Я хотел бы апельсиновый сок.','Я хоте́л бы апельси́новый сок.','Ya khotel by apelsinovyy sok.','I would like orange juice.','Chciałbym sok pomarańczowy.','Ich hätte gern Orangensaft.',60),
('orderingfood-part-1-61','orderingfood-part-1','Можно без льда?','Мо́жно без льда́?','Mozhno bez lda?','Can it be without ice?','Czy może być bez lodu?','Ohne Eis, bitte?',61),
('orderingfood-part-1-62','orderingfood-part-1','Я готов сделать заказ.','Я гото́в сде́лать зака́з.','Ya gotov sdelat zakaz.','I am ready to order.','Jestem gotowy zamówić.','Ich bin bereit zu bestellen.',62),
('orderingfood-part-1-63','orderingfood-part-1','Я начну с супа.','Я начну́ с су́па.','Ya nachnu s supa.','I will start with a soup.','Zacznę od zupy.','Ich beginne mit einer Suppe.',63),
('orderingfood-part-1-64','orderingfood-part-1','Какой суп сегодня?','Како́й суп сего́дня?','Kakoy sup segodnya?','What soup do you have today?','Jaką zupę macie dzisiaj?','Welche Suppe haben Sie heute?',64),
('orderingfood-part-1-65','orderingfood-part-1','Сегодня томатный суп.','Сего́дня тома́тный суп.','Segodnya tomatnyy sup.','Today we have tomato soup.','Dzisiaj mamy zupę pomidorową.','Heute haben wir Tomatensuppe.',65),
('orderingfood-part-1-66','orderingfood-part-1','Я возьму томатный суп.','Я возьму́ тома́тный суп.','Ya vozmu tomatnyy sup.','I will take the tomato soup.','Wezmę zupę pomidorową.','Ich nehme die Tomatensuppe.',66),
('orderingfood-part-1-67','orderingfood-part-1','Что вы рекомендуете на второе?','Что вы рекоменду́ете на второ́е?','Chto vy rekomenduyete na vtoroye?','What do you recommend as a main course?','Co polecacie na danie główne?','Was empfehlen Sie als Hauptgericht?',67),
('orderingfood-part-1-68','orderingfood-part-1','Я люблю курицу.','Я люблю́ ку́рицу.','Ya lyublyu kuritsu.','I like chicken.','Lubię kurczaka.','Ich mag Hähnchen.',68),
('orderingfood-part-1-69','orderingfood-part-1','Я люблю рыбу.','Я люблю́ ры́бу.','Ya lyublyu rybu.','I like fish.','Lubię ryby.','Ich mag Fisch.',69),
('orderingfood-part-1-70','orderingfood-part-1','Это блюдо подаётся с рисом.','Э́то блю́до подаётся с ри́сом.','Eto blyudo podayotsya s risom.','This dish is served with rice.','To danie jest podawane z ryżem.','Dieses Gericht wird mit Reis serviert.',70),
('orderingfood-part-1-71','orderingfood-part-1','Можно заменить рис на картофель?','Мо́жно замени́ть рис на карто́фель?','Mozhno zamenit ris na kartofel?','Can I replace the rice with potatoes?','Czy mogę zamienić ryż na ziemniaki?','Kann ich den Reis durch Kartoffeln ersetzen?',71),
('orderingfood-part-1-72','orderingfood-part-1','Да, это возможно.','Да, э́то возмо́жно.','Da, eto vozmozhno.','Yes, that is possible.','Tak, to możliwe.','Ja, das ist möglich.',72),
('orderingfood-part-1-73','orderingfood-part-1','Я не люблю острое.','Я не люблю́ о́строе.','Ya ne lyublyu ostroye.','I do not like spicy food.','Nie lubię ostrych potraw.','Ich mag kein scharfes Essen.',73),
('orderingfood-part-1-74','orderingfood-part-1','Это блюдо острое?','Э́то блю́до о́строе?','Eto blyudo ostroye?','Is this dish spicy?','Czy to danie jest ostre?','Ist dieses Gericht scharf?',74),
('orderingfood-part-1-75','orderingfood-part-1','Нет, оно не острое.','Нет, оно́ не о́строе.','Net, ono ne ostroye.','No, it is not spicy.','Nie, nie jest ostre.','Nein, es ist nicht scharf.',75),
('orderingfood-part-1-76','orderingfood-part-1','Я хотел бы попробовать это.','Я хоте́л бы попро́бовать э́то.','Ya khotel by poprobovat eto.','I would like to try that.','Chciałbym tego spróbować.','Ich würde das gern probieren.',76),
('orderingfood-part-1-77','orderingfood-part-1','Еда выглядит очень аппетитно.','Еда́ вы́глядит о́чень аппети́тно.','Yeda vyglyadit ochen appetitno.','The food looks very appetizing.','Jedzenie wygląda bardzo apetycznie.','Das Essen sieht sehr appetitlich aus.',77),
('orderingfood-part-1-78','orderingfood-part-1','Порция очень большая.','По́рция о́чень больша́я.','Portsiya ochen bolshaya.','The portion is very large.','Porcja jest bardzo duża.','Die Portion ist sehr groß.',78),
('orderingfood-part-1-79','orderingfood-part-1','Я не могу всё съесть.','Я не могу́ всё съе́сть.','Ya ne mogu vsyo syest.','I cannot eat all of it.','Nie mogę tego wszystkiego zjeść.','Ich kann nicht alles aufessen.',79),
('orderingfood-part-1-80','orderingfood-part-1','Можно взять это с собой?','Мо́жно взять э́то с собо́й?','Mozhno vzyat eto s soboy?','Can I take this to go?','Czy mogę zabrać to na wynos?','Kann ich das zum Mitnehmen bekommen?',80),
('orderingfood-part-1-81','orderingfood-part-1','Конечно, мы упакуем это.','Коне́чно, мы упаку́ем э́то.','Konechno, my upakuyem eto.','Of course, we will pack it.','Oczywiście, zapakujemy to.','Natürlich, wir packen es ein.',81),
('orderingfood-part-1-82','orderingfood-part-1','Мне очень понравился ужин.','Мне о́чень понра́вился у́жин.','Mne ochen ponravilsya uzhin.','I really liked the dinner.','Bardzo podobała mi się kolacja.','Das Abendessen hat mir sehr gefallen.',82),
('orderingfood-part-1-83','orderingfood-part-1','Обслуживание было отличным.','Обслу́живание бы́ло отли́чным.','Obsluzhivaniye bylo otlichnym.','The service was excellent.','Obsługa była doskonała.','Der Service war ausgezeichnet.',83),
('orderingfood-part-1-84','orderingfood-part-1','Спасибо за рекомендацию.','Спаси́бо за рекоменда́цию.','Spasibo za rekomendatsiyu.','Thank you for the recommendation.','Dziękuję za rekomendację.','Danke für die Empfehlung.',84),
('orderingfood-part-1-85','orderingfood-part-1','Мы обязательно вернёмся.','Мы обяза́тельно вернёмся.','My obyazatelno vernyomsya.','We will definitely come back.','Na pewno wrócimy.','Wir kommen bestimmt wieder.',85),
('orderingfood-part-1-86','orderingfood-part-1','Можно разделить счёт?','Мо́жно раздели́ть счёт?','Mozhno razdelit schyot?','Can we split the bill?','Czy możemy podzielić rachunek?','Können wir die Rechnung teilen?',86),
('orderingfood-part-1-87','orderingfood-part-1','Каждый заплатит за себя.','Ка́ждый запла́тит за себя́.','Kazhdyy zaplatit za sebya.','Everyone will pay for themselves.','Każdy zapłaci za siebie.','Jeder bezahlt für sich selbst.',87),
('orderingfood-part-1-88','orderingfood-part-1','Я оставлю чаевые.','Я оста́влю чаевы́е.','Ya ostavlyu chayevyye.','I will leave a tip.','Zostawię napiwek.','Ich werde Trinkgeld geben.',88),
('orderingfood-part-1-89','orderingfood-part-1','Сколько стоят чаевые обычно?','Ско́лько сто́ят чаевы́е обы́чно?','Skolko stoyat chayevyye obychno?','How much is the usual tip?','Ile zwykle wynosi napiwek?','Wie hoch ist das übliche Trinkgeld?',89),
('orderingfood-part-1-90','orderingfood-part-1','Обычно около десяти процентов.','Обы́чно о́коло десяти́ проце́нтов.','Obychno okolo desyati protsentov.','Usually around ten percent.','Zwykle około dziesięciu procent.','Normalerweise etwa zehn Prozent.',90),
('orderingfood-part-1-91','orderingfood-part-1','Ресторан закрывается скоро.','Рестора́н закрыва́ется ско́ро.','Restoran zakryvayetsya skoro.','The restaurant is closing soon.','Restauracja wkrótce się zamyka.','Das Restaurant schließt bald.',91),
('orderingfood-part-1-92','orderingfood-part-1','Нам пора идти.','Нам пора́ идти́.','Nam pora idti.','It is time for us to go.','Pora już iść.','Es ist Zeit zu gehen.',92),
('orderingfood-part-1-93','orderingfood-part-1','Спасибо за прекрасный вечер.','Спаси́бо за прекра́сный ве́чер.','Spasibo za prekrasnyy vecher.','Thank you for a wonderful evening.','Dziękujemy za wspaniały wieczór.','Danke für einen wunderschönen Abend.',93),
('orderingfood-part-1-94','orderingfood-part-1','До свидания.','До свида́ния.','Do svidaniya.','Goodbye.','Do widzenia.','Auf Wiedersehen.',94),
('orderingfood-part-1-95','orderingfood-part-1','Хорошего дня.','Хоро́шего дня.','Khoroshego dnya.','Have a nice day.','Miłego dnia.','Einen schönen Tag noch.',95),
('orderingfood-part-1-96','orderingfood-part-1','Мы довольны рестораном.','Мы дово́льны рестора́ном.','My dovolny restoranom.','We are satisfied with the restaurant.','Jesteśmy zadowoleni z restauracji.','Wir sind mit dem Restaurant zufrieden.',96),
('orderingfood-part-1-97','orderingfood-part-1','Я расскажу друзьям об этом месте.','Я расскажу́ друзья́м об э́том ме́сте.','Ya rasskazhu druzyam ob etom meste.','I will tell my friends about this place.','Opowiem znajomym o tym miejscu.','Ich werde meinen Freunden von diesem Ort erzählen.',97),
('orderingfood-part-1-98','orderingfood-part-1','Мы обязательно придём снова.','Мы обяза́тельно придём сно́ва.','My obyazatelno pridyom snova.','We will definitely come again.','Na pewno przyjdziemy ponownie.','Wir werden auf jeden Fall wiederkommen.',98),
('orderingfood-part-1-99','orderingfood-part-1','Это был отличный ресторан.','Э́то был отли́чный рестора́н.','Eto byl otlichnyy restoran.','It was an excellent restaurant.','To była świetna restauracja.','Es war ein ausgezeichnetes Restaurant.',99),
('orderingfood-part-1-100','orderingfood-part-1','Ужин был незабываемым.','У́жин был незабыва́емым.','Uzhin byl nezabyvayemym.','The dinner was unforgettable.','Kolacja była niezapomniana.','Das Abendessen war unvergesslich.',100)
